const typingPhrases = ["MCA Student", "Web Developer", "Software Developer", "Problem Solver", "Tech Enthusiast"];
let tpIdx=0, tpChar=0, tpDeleting=false;
function typeLoop(){
  const el=document.getElementById("typingText");
  if(!el) return;
  const phrase=typingPhrases[tpIdx];
  if(tpDeleting){ el.textContent=phrase.slice(0,--tpChar); }
  else { el.textContent=phrase.slice(0,++tpChar); }
  if(!tpDeleting && tpChar===phrase.length){ setTimeout(()=>{tpDeleting=true;typeLoop();},1600); return; }
  if(tpDeleting && tpChar===0){ tpDeleting=false; tpIdx=(tpIdx+1)%typingPhrases.length; }
  setTimeout(typeLoop, tpDeleting?60:100);
}
typeLoop();

// ── PROGRESS BAR ──
window.addEventListener("scroll",()=>{
  const bar=document.getElementById("progressBar");
  const bt=document.getElementById("backTop");
  const pct=(window.scrollY/(document.body.scrollHeight-window.innerHeight))*100;
  if(bar) bar.style.width=pct+"%";
  if(bt){ bt.classList.toggle("show", window.scrollY>300); }
});

// ── ACTIVE NAV ──
const sections=document.querySelectorAll("section[id]");
const navLinks=document.querySelectorAll(".nav-links a");
window.addEventListener("scroll",()=>{
  let cur="";
  sections.forEach(s=>{ if(window.scrollY>=s.offsetTop-120) cur=s.id; });
  navLinks.forEach(a=>{ a.classList.toggle("active", a.getAttribute("href")==="#"+cur); });
});

