// ── CERT MODAL DATA ──
const certData={
  cert1:{ title:"Java Programming Certification", org:"CSC Computer Software College · Grade A · 2023", img:"data:image/jpeg;base64,", credly:null },
  cert2:{ title:"Python Essentials 1", org:"Cisco Networking Academy · Dec 2025", img:"data:image/jpeg;base64,", credly:null },
  cert3:{ title:"AWS Academy Cloud Foundations", org:"AWS Academy · Apr 2026 · 20 hours", img:"data:image/jpeg;base64,", credly:"https://www.credly.com/go/IRN3DAjx" }
};
function openCert(id){
  const d=certData[id];
  document.getElementById("certModalTitle").textContent=d.title;
  const body=document.getElementById("certModalBody");
  if(d.img){
    body.innerHTML='<img class="cert-modal-img" src="'+d.img+'" alt="'+d.title+'">'+'<div class="cert-upload-note">🏛 '+d.org+'</div>';
  } else {
    body.innerHTML='<div class="cert-modal-pdf-placeholder"><span class="pdf-icon">📜</span><div style="font-size:1.1rem;color:var(--white);font-weight:600">'+d.title+'</div><div style="font-size:0.8rem">'+d.org+'</div></div><div class="cert-upload-note">⚠ Certificate image not yet embedded. Upload your certificate image/PDF to the developer to embed it here.</div>';
  }
  document.getElementById("certModal").classList.add("open");
  document.body.style.overflow="hidden";
}
function closeCertModal(e){
  if(!e||e.target===document.getElementById("certModal")||e.target.classList.contains("cert-modal-close")){
    document.getElementById("certModal").classList.remove("open");
    document.body.style.overflow="";
  }
}
document.addEventListener("keydown",e=>{ if(e.key==="Escape") closeCertModal({target:document.getElementById("certModal")}); });

// ── PARTICLE CANVAS ──
const canvas = document.getElementById('bg-canvas');
const ctx = canvas.getContext('2d');
let W, H, particles = [];

function resize() {
  W = canvas.width  = window.innerWidth;
  H = canvas.height = window.innerHeight;
}
resize();
window.addEventListener('resize', resize);

class Particle {
  constructor() { this.reset(); }
  reset() {
    this.x = Math.random() * W;
    this.y = Math.random() * H;
    this.size = Math.random() * 1.5 + 0.3;
    this.speedX = (Math.random() - 0.5) * 0.3;
    this.speedY = (Math.random() - 0.5) * 0.3;
    this.opacity = Math.random() * 0.5 + 0.1;
    this.color = Math.random() > 0.7 ? '#ffd700' : '#00d4ff';
  }
  update() {
    this.x += this.speedX;
    this.y += this.speedY;
    if (this.x < 0 || this.x > W || this.y < 0 || this.y > H) this.reset();
  }
  draw() {
    ctx.beginPath();
    ctx.arc(this.x, this.y, this.size, 0, Math.PI*2);
    ctx.fillStyle = this.color;
    ctx.globalAlpha = this.opacity;
    ctx.fill();
  }
}

for (let i = 0; i < 120; i++) particles.push(new Particle());

function animate() {
  ctx.clearRect(0,0,W,H);
  // draw grid lines
  ctx.globalAlpha = 0.03;
  ctx.strokeStyle = '#00d4ff';
  ctx.lineWidth = 0.5;
  for (let x = 0; x < W; x += 80) {
    ctx.beginPath(); ctx.moveTo(x,0); ctx.lineTo(x,H); ctx.stroke();
  }
  for (let y = 0; y < H; y += 80) {
    ctx.beginPath(); ctx.moveTo(0,y); ctx.lineTo(W,y); ctx.stroke();
  }
  particles.forEach(p => { p.update(); p.draw(); });
  ctx.globalAlpha = 1;
  requestAnimationFrame(animate);
}
animate();

// ── SCROLL REVEAL ──
const reveals = document.querySelectorAll('.reveal');
const observer = new IntersectionObserver((entries) => {
  entries.forEach(e => { if (e.isIntersecting) e.target.classList.add('visible'); });
}, { threshold: 0.1 });
reveals.forEach(r => observer.observe(r));

